import math
class Solution:
    def subarrayLCM(self, nums, k):
        n = len(nums)
        count = 0
        for i in range(n):
            cur = 1
            for j in range(i, n):
                cur = cur * nums[j] // math.gcd(cur, nums[j])
                if cur == k:
                    count += 1
                elif cur > k:
                    break
        return count

