from math import gcd
class Solution:
    def subarrayLCM(self, nums, k):
        n = len(nums)
        ans = 0
        for i in range(n):
            cur = 1
            for j in range(i, n):
                g = gcd(cur, nums[j])
                cur = cur // g * nums[j]
                if cur > k:
                    break
                if cur == k:
                    ans += 1
        return ans

