var subarrayLCM = function(nums, k) {
    const gcd = (a, b) => { while (b) { [a, b] = [b, a % b]; } return a; };
    const n = nums.length;
    let ans = 0;
    for (let i = 0; i < n; i++) {
        let cur = 1;
        for (let j = i; j < n; j++) {
            const g = gcd(cur, nums[j]);
            cur = (cur / g) * nums[j];
            if (cur > k) break;
            if (cur === k) ans++;
        }
    }
    return ans;
};
